queries.sparql:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?style_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasStyles ?child ; p:hasHair_Stylists ?parent . } GROUP BY ?child }
  ?child p:style_name ?style_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Hair_Stylists } }
  FILTER(?nf = ?total)
}

